mapper.update:
update t_question_import_batch
set received_chunk_count = received_chunk_count + #{chunkIncrement},
    total_row_count = total_row_count + #{rowIncrement},
    updated_time = now()
where id = #{id,jdbcType=BIGINT}
  and status = #{expectedStatus,jdbcType=VARCHAR}

update t_question_import_batch
set status = 'FAILED',
    error_message = #{errorMessage,jdbcType=VARCHAR},
    updated_time = now()
where id = #{id,jdbcType=BIGINT}
  and status = #{expectedStatus,jdbcType=VARCHAR}

update t_question_import_batch
set status = 'READY',
    expected_chunk_count = #{expectedChunkCount,jdbcType=INTEGER},
    updated_time = now()
where id = #{id,jdbcType=BIGINT}
  and status = #{expectedStatus,jdbcType=VARCHAR}
  and received_chunk_count = #{expectedChunkCount,jdbcType=INTEGER}
  and total_row_count = #{expectedRowCount,jdbcType=INTEGER}

update t_question_import_batch
set status = 'COMMITTED',
    imported_count = #{importedCount,jdbcType=INTEGER},
    updated_time = now()
where id = #{id,jdbcType=BIGINT}
  and status = #{expectedStatus,jdbcType=VARCHAR}

mapper.select:
select id
from t_question_import_batch
where status = #{status,jdbcType=VARCHAR}
  and updated_time < #{updatedBefore,jdbcType=TIMESTAMP}
order by updated_time asc
limit #{limit,jdbcType=INTEGER}

